import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(minutes=30)
    }
    
    secret_key = 'your_secret_key_here'  # Replace with your own secret key
    return jwt.encode(payload, secret_key, algorithm='HS256')

def verify_jwt(token):
    try:
        payload = jwt.decode(token, 'your_secret_key_here', algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

# Example usage:
user_id = 1
role = 'admin'
token = generate_jwt(user_id, role)
print(token)

verified_payload = verify_jwt(token)
if verified_payload is not None:
    print('User ID:', verified_payload['user_id'])
    print('Role:', verified_payload['role'])
else:
    print('Invalid or expired token')